for html_file in glob.glob('*.html'):
    with open(html_file, 'r') as f:
        content = f.read()
    
    for emoji, svg in svg_map.items():
        content = content.replace(emoji, svg)
        
    with open(html_file, 'w') as f:
        f.write(content)

print("Replaced all emojis with SVGs!")
